const message = $json.message || {};
let data = {};
let found = false;

const looksValid = (obj = {}) => {
  const required = ['appointmentType', 'appointmentDateTime', 'callerName'];
  return required.every(k => obj?.[k]);
};

if (!found && looksValid(message.analysis?.structuredData)) {
  data = message.analysis.structuredData;
  found = true;
}

return [
  {
    json: {
      ...$json,
      structuredData: data,
      hasStructuredData: found
    }
  }
];
